import Link from 'next/link'
import { useSession } from 'next-auth/react'
import { FormEvent, useEffect, useState } from 'react'
import type { RetrievalQueryResponse } from '../lib/contracts/api'

type RefCard = { id: string; title: string; sourceName: string | null; uploadedAt: string }

export default function PortalHome() {
  const { data: session } = useSession()
  const [query, setQuery] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [featured, setFeatured] = useState<RefCard[]>([])
  const [recent, setRecent] = useState<RefCard[]>([])
  const [results, setResults] = useState<RetrievalQueryResponse['results']>([])

  useEffect(() => {
    Promise.all([
      fetch('/api/references/library?featured=true&limit=6').then((r) => r.json()),
      fetch('/api/references/library?recent=true&limit=6').then((r) => r.json()),
    ])
      .then(([f, rr]) => {
        setFeatured(f.items || [])
        setRecent(rr.items || [])
      })
      .catch(() => undefined)
  }, [])

  async function onSearch(e: FormEvent) {
    e.preventDefault()
    if (!query.trim()) return
    setLoading(true)
    setError(null)
    try {
      const res = await fetch('/api/references/query', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ query, topK: 8, page: 1 }),
      })
      const data = (await res.json()) as RetrievalQueryResponse
      if (!res.ok) throw new Error((data as any).error || 'search failed')
      setResults(data.results)
    } catch (err: any) {
      setError(err?.message || 'search failed')
    } finally {
      setLoading(false)
    }
  }

  return (
    <main className="mx-auto max-w-6xl px-6 py-10">
      <header className="mb-8 flex items-center justify-between">
        <h1 className="text-3xl font-bold">Knowledge Portal</h1>
        <nav className="flex items-center gap-4">
          <Link href="/create" className="rounded bg-black px-4 py-2 text-white">Create Content</Link>
          {(session as any)?.user?.role === 'admin' ? (
            <Link href="/admin/dashboard" className="rounded border px-4 py-2">Admin Access</Link>
          ) : null}
        </nav>
      </header>

      <section className="mb-10 rounded border bg-gray-50 p-6">
        <form onSubmit={onSearch} className="flex flex-col gap-3 md:flex-row">
          <input
            className="w-full rounded border px-4 py-3"
            placeholder="Search verified medical knowledge..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
          />
          <button disabled={loading || !query.trim()} className="rounded bg-blue-600 px-5 py-3 text-white disabled:opacity-50">
            {loading ? 'Searching...' : 'Search'}
          </button>
        </form>
        {error ? <p className="mt-3 text-sm text-red-700">{error}</p> : null}
        {results.length > 0 ? (
          <div className="mt-5 space-y-3">
            {results.map((r) => (
              <article key={r.id} className="rounded border bg-white p-3">
                <Link href={`/reference/${r.reference.id}`} className="font-semibold hover:underline">{r.reference.title || 'Untitled'}</Link>
                <p className="text-sm text-gray-700">{r.snippet}</p>
                <div className="mt-1 text-xs text-green-700">Verified</div>
              </article>
            ))}
            <Link href={`/search?q=${encodeURIComponent(query)}`} className="inline-block text-sm underline">Open full results</Link>
          </div>
        ) : null}
      </section>

      <section className="mb-10">
        <h2 className="mb-3 text-xl font-semibold">Featured Verified References</h2>
        <div className="grid gap-3 md:grid-cols-2">
          {featured.map((ref) => (
            <Link key={ref.id} href={`/reference/${ref.id}`} className="rounded border p-3 hover:bg-gray-50">
              <h3 className="font-medium">{ref.title}</h3>
              <p className="text-sm text-gray-600">{ref.sourceName || 'Unknown source'}</p>
            </Link>
          ))}
        </div>
      </section>

      <section>
        <h2 className="mb-3 text-xl font-semibold">Recently Verified</h2>
        <ul className="space-y-2">
          {recent.map((ref) => (
            <li key={ref.id} className="rounded border p-3">
              <Link href={`/reference/${ref.id}`} className="font-medium hover:underline">{ref.title}</Link>
              <div className="text-xs text-gray-500">{new Date(ref.uploadedAt).toLocaleString()}</div>
            </li>
          ))}
        </ul>
      </section>
    </main>
  )
}
